  if id_collision_count <> 0 then raise exception 'PKG-06E id collision count: %', id_collision_count; end if;
end $$;

insert into public.card_printings (
  id,
  card_print_id,
  finish_key,
  is_provisional,
  provenance_source,
  provenance_ref,
  created_by
)
select
  card_printing_id,
  card_print_id,
  finish_key,
  false,
  provenance_source,
  provenance_ref,
  created_by
from pkg06e_active_child_printings;

select
  'PKG-06E-ACTIVE-FINISH-CHILD-PRINTING-INSERTS'::text as package_id,
  '0a1a320527119d55a012ae2a564059993f48b83220591cd522f6ca9119393a32'::text as source_readiness_fingerprint,
  '87af87fa1a17297509296b6a06d421ec8840a8323d6f348bff01817962408aa6'::text as package_fingerprint,
  (select count(distinct set_key) from pkg06e_active_child_printings)::int as planned_sets,
  (select count(distinct card_print_id) from pkg06e_active_child_printings)::int as target_parent_rows,
  (select count(*) from pkg06e_active_child_printings)::int as planned_child_rows;

rollback;
